BEGIN TRANSACTION;
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE "loja_categoria" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(120) NOT NULL UNIQUE, "slug" varchar(140) NOT NULL UNIQUE, "parent_id" bigint NULL REFERENCES "loja_categoria" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_cliente" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(200) NOT NULL, "cpf" varchar(14) NULL UNIQUE, "telefone" varchar(20) NOT NULL, "email" varchar(254) NOT NULL, "endereco" varchar(300) NOT NULL, "bairro" varchar(100) NOT NULL, "limite_credito" decimal NOT NULL, "situacao" varchar(20) NOT NULL, "observacao" text NOT NULL, "criado_em" datetime NOT NULL);
CREATE TABLE "loja_contapagar" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "fornecedor" varchar(200) NOT NULL, "referencia" varchar(220) NOT NULL, "valor_total" decimal NOT NULL, "valor_pago" decimal NOT NULL, "vencimento" date NOT NULL, "status" varchar(10) NOT NULL, "observacao" varchar(300) NOT NULL, "criado_em" datetime NOT NULL, "data_pagamento" date NULL, "grupo_referencia" varchar(40) NOT NULL, "parcela_numero" integer unsigned NOT NULL CHECK ("parcela_numero" >= 0), "parcelas_total" integer unsigned NOT NULL CHECK ("parcelas_total" >= 0));
CREATE TABLE "loja_fiadoconta" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "referencia" varchar(200) NOT NULL, "valor_total" decimal NOT NULL, "valor_pago" decimal NOT NULL, "vencimento" date NOT NULL, "status" varchar(10) NOT NULL, "observacao" varchar(300) NOT NULL, "criado_em" datetime NOT NULL, "cliente_id" bigint NOT NULL REFERENCES "loja_cliente" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_itempedido" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "quantidade" integer unsigned NOT NULL CHECK ("quantidade" >= 0), "preco_unitario" decimal NOT NULL, "produto_id" bigint NOT NULL REFERENCES "loja_produto" ("id") DEFERRABLE INITIALLY DEFERRED, "pedido_id" bigint NOT NULL REFERENCES "loja_pedido" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_itemvenda" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "quantidade" integer unsigned NOT NULL CHECK ("quantidade" >= 0), "preco_unitario" decimal NOT NULL, "produto_id" bigint NOT NULL REFERENCES "loja_produto" ("id") DEFERRABLE INITIALLY DEFERRED, "venda_id" bigint NOT NULL REFERENCES "loja_venda" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_movimentacaoestoque" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "tipo" varchar(10) NOT NULL, "quantidade" integer NOT NULL, "observacao" varchar(300) NOT NULL, "responsavel" varchar(150) NOT NULL, "data" datetime NOT NULL, "produto_id" bigint NOT NULL REFERENCES "loja_produto" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_pedido" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "cliente_nome" varchar(200) NOT NULL, "cliente_endereco" varchar(300) NOT NULL, "forma_pagamento" varchar(20) NOT NULL, "observacao" text NOT NULL, "desconto" decimal NOT NULL, "status" varchar(15) NOT NULL, "criado_em" datetime NOT NULL);
CREATE TABLE "loja_produto" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "codigo" varchar(60) NOT NULL, "nome" varchar(200) NOT NULL, "slug" varchar(220) NOT NULL UNIQUE, "descricao" text NOT NULL, "custo" decimal NOT NULL, "preco" decimal NOT NULL, "estoque" integer unsigned NOT NULL CHECK ("estoque" >= 0), "estoque_minimo" integer unsigned NOT NULL CHECK ("estoque_minimo" >= 0), "ativo" bool NOT NULL, "vendas" integer unsigned NOT NULL CHECK ("vendas" >= 0), "imagem" varchar(100) NULL, "criado_em" datetime NOT NULL, "categoria_id" bigint NULL REFERENCES "loja_categoria" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "loja_venda" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "data" datetime NOT NULL, "forma_pagamento" varchar(20) NOT NULL, "status" varchar(15) NOT NULL, "desconto" decimal NOT NULL, "observacao" text NOT NULL, "criado_em" datetime NOT NULL, "cliente_id" bigint NULL REFERENCES "loja_cliente" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE UNIQUE INDEX "auth_group_permissions_group_id_permission_id_0cd325b0_uniq" ON "auth_group_permissions" ("group_id", "permission_id");
